import React from "react"
import { MDXRenderer } from "gatsby-plugin-mdx"
import { GatsbyImage, getSrc } from "gatsby-plugin-image"
import { useIntl } from "gatsby-plugin-intl"
import Link from "../IntlLink"
import Share from "../Share"
import FA from "../FA"

import classNames from "classnames/bind"
import styles from "./styles.module.scss"

export default function Body({ title, collection, cover, hidecover, excerpt, prebody, body, children, pdf, video, disclaimer=false, shareBottom, topics, tags, lang }) {
	
	const cx = classNames.bind(styles);
	const intl = useIntl()

	return(
		<div className={cx("body")}>
			{cover && 
				<div className={cx("cover")}>
					{!hidecover && <GatsbyImage image={cover.childImageSharp.gatsbyImageData} alt={title || "ภาพประกอบ"} />}
					<span hidden data-typesense-field="img_url">{getSrc(cover.childImageSharp.thumbnail)}</span>
				</div>
			}
			{excerpt &&
				<div className={cx("excerpt")} data-typesense-field="body">{excerpt}</div>
			}
			{prebody}
			{body &&
				<MDXRenderer>{body}</MDXRenderer>
			}
			{children}
			<div className={cx("endmatter")}>
				{pdf &&
					<div className={cx("section")}>
						<a href={pdf.publicURL} target="_blank" rel="nofollow noopener noreferrer"><span className="inline-svg"><FA icon="page" /></span> Download full text</a>
					</div>
				}
				{video &&
					<div className={cx("section", "noprint")}>
						<a href={video} target="_blank" rel="nofollow noopener noreferrer"><span className="inline-svg"><FA icon="youtube" /></span> {lang === "th" ? "ชมคลิปวีดีโอ" : "Watch recording"}</a>
					</div>
				}
				{shareBottom &&
					<div className={cx("section", "share", "noprint")}>
						<Share inline={true} />
					</div>
				}
				{disclaimer &&
					<div className={cx("section")}>
						<em>{intl.formatMessage({ id: collection === "workshops" ? "disclaimer_workshops" : "disclaimer" })}</em>
					</div>
				}
				{topics && // TODO: hanging indent
					<div className={cx("section")}>
						<span className={cx("right-margin", "header")}>Topics: </span>
						{topics.map((topic, i) =>
							<Link to={`/search/?topics=${topic}`} key={`topic${i}`}>
								<span className="blob" data-typesense-field="topics">{topic}</span>
							</Link>
						)}
					</div>
				}
				{tags &&
					<div className={cx("section")}>
						<span className={cx("right-margin", "header")}>Tags: </span>
						{tags.map((tag, i) =>
							<Link to={`/search/?tags=${tag}`} key={`tag${i}`}>
								<span className="blob" data-typesense-field="tags">{tag}</span>
							</Link>
						)}
					</div>
				}
			</div>
		</div>
	)

}