import React from "react"
import Author, { AdditionalAuthor } from "../Author"
import DateShareTitle from "../DateShareTitle"
import Body from "../Body"
import { getAuthors } from "../../util"

import classNames from "classnames/bind"
import styles from "./styles.module.scss"

export default function LayoutPub({
	frontmatter,
	collection,
	date=frontmatter.date,
	title=frontmatter.title,
	subtitle=frontmatter.subtitle,
	cover=frontmatter.cover,
	excerpt=frontmatter.excerpt,
	topics=frontmatter.topics,
	tags=frontmatter.tags,
	layout=frontmatter.layout,
	hidecover=frontmatter.hidecover,
	pdf=frontmatter.pdf,
	video=frontmatter.video,
	disclaimer,
	shareBottom=true,
	prebody, body, authors, discussants, lang, children
}) {

	const cx = classNames.bind(styles);

	const sortedAuthors = authors && getAuthors(frontmatter.authors, authors, lang)
	const sortedDiscussants = discussants && getAuthors(frontmatter.discussants, discussants, lang)
	const hasAuthors = sortedAuthors && sortedAuthors.length > 0

	return (
		<React.Fragment>
			<DateShareTitle
				frontmatter={frontmatter}
				collection={collection}
				date={date}
				title={title}
				subtitle={subtitle}
				lang={lang}
			/>
			<div className={cx("grid", {onecol: (layout === "onecol") || !hasAuthors})}>
				<Body
					title={title}
					collection={collection}
					cover={cover}
					hidecover={hidecover}
					excerpt={excerpt}
					prebody={prebody}
					body={body}
					children={children}
					pdf={pdf}
					video={video}
					disclaimer={disclaimer || frontmatter.disclaimer || hasAuthors}
					topics={topics}
					tags={tags}
					shareBottom={shareBottom}
					lang={lang}
				/>
				{(sortedAuthors || sortedDiscussants) &&
					<div className={cx("sidebar")}>
						<div className={cx("authors")}>
							{sortedAuthors && sortedAuthors.map((author, i) =>
								<div className={cx("authorCard")} key={`author${i}`}>
									{author.frontmatter
										? <Author
												author={author.frontmatter}
												link={author.fields.slug}
												flexible={true}
												typesenseField={"authors"}
												lang={lang}
											/>
										: <Author name={author} />
									}
								</div>
							)}
						</div>
						{sortedDiscussants && sortedDiscussants.length > 0 &&
							<div>
								<h6>{lang === "th" ? "ผู้วิจารณ์" : (sortedDiscussants.length > 1 ? "Discussants" : "Discussant")}</h6>
								<div className={cx("authors")}>
									{sortedDiscussants.map((author, i) =>
										<div className={cx("authorCard")} key={`author${i}`}>
											<Author
												author={author.frontmatter}
												link={author.fields.slug}
												flexible={true}
												typesenseField={"authors"}
												lang={lang}
											/>
										</div>
									)}
								</div>
							</div>
						}
					</div>
				}
			</div>
		</React.Fragment>
	)

}