import React from "react"
import { graphql } from "gatsby"
import Layout from "../../components/Layout"
import LayoutPub from "../../components/LayoutPub"

export default function PageTemplate({ pageContext: { language }, data: { meta, mdx } }) {

	const metadata = meta.siteMetadata.collections.filter(c => c.collection === mdx.fields.collection)[0]
	const seriesPlaceholder = meta.siteMetadata.series.filter(s => s.series === mdx.frontmatter.series)

	return (
		<Layout
			lang={language}
			mdx={mdx}
			metadata={metadata}
			placeholder={(seriesPlaceholder.length > 0 && seriesPlaceholder[0].placeholder) || undefined}
		>
			<LayoutPub
				frontmatter={mdx.frontmatter}
				collection={mdx.fields.collection}
				authors={mdx.authors}
				discussants={mdx.discussants}
				body={mdx.body}
				lang={language}
				// disclaimer={mdx.frontmatter.disclaimer}
				shareBottom={false} // too short
				prebody={
					<React.Fragment>
						{/* <div>
							{formatFrontmatterDate(mdx.frontmatter, language)}
							{language === "th"
								? <React.Fragment> เวลา </React.Fragment>
								: <React.Fragment>, </React.Fragment>
							}
							{timeFromNum(mdx.frontmatter.time_start)}–{timeFromNum(mdx.frontmatter.time_end)}
						</div> */}
					</React.Fragment>
				}
			/>
		</Layout>
	)

}

export const pageQuery = graphql`
	query SeminarQuery($id: String) {
		meta: site {
			siteMetadata {
				collections {
					collection
					title
					subtitle
					url
					placeholder
				}
				series {
					series
					placeholder
				}
			}
		}
		mdx(id: { eq: $id }) {
			body
			frontmatter {
        date
        title
        series
        authors
				discussants
        time_start
        time_end
        location
				disclaimer
				video
				cover {
					publicURL
					childImageSharp {
						gatsbyImageData(layout: FULL_WIDTH)
						thumbnail: gatsbyImageData(layout: CONSTRAINED, width: 160, height: 160)
					}
				}
      }
      fields {
				collection
        slug
				shorturl
      }
      authors {
        frontmatter {
          memberid
          title
          org
          email
          image {
						childImageSharp {
							gatsbyImageData(layout: CONSTRAINED, width: 200, height: 200)
						}
          }
					exclude
        }
        fields {
          slug
          lang
        }
      }
			discussants {
        frontmatter {
          memberid
          title
          org
          email
          image {
            publicURL
            childImageSharp {
							gatsbyImageData(layout: CONSTRAINED, width: 200, height: 200)
            }
          }
        }
        fields {
          slug
          lang
        }
      }
		}
	}
`