import React from "react"
import { formatFrontmatterDate } from "../../util"
import Link from "../IntlLink"
import FA from "../FA"
import kebabCase from "lodash/kebabCase"

import classNames from "classnames/bind"
import styles from "./styles.module.scss"

export default function DateShareTitle({ frontmatter, collection, date, title, subtitle, lang }) {

	const cx = classNames.bind(styles);

	date = date || frontmatter.date
	title = title || frontmatter.title
	subtitle = subtitle || frontmatter.subtitle || frontmatter.location

	return(
		<div className={cx("datesharetitle")}>
			<div className={cx("top")}>
				<div className="date" data-typesense-field="date_formatted">
					{frontmatter && (date === frontmatter.date) ? formatFrontmatterDate(frontmatter, lang) : date}
				</div>
				{frontmatter && frontmatter.date && <span hidden data-typesense-field="year">{frontmatter.date.substring(0, 4)}</span>}
				{frontmatter && frontmatter.date && <span hidden data-typesense-field="date">{Date.parse(frontmatter.date)}</span>}
				{frontmatter && frontmatter.updated && <span hidden data-typesense-field="updated">{Date.parse(frontmatter.updated)}</span>}
				<div className={cx("share")}>
					{/* <Share /> */}
				</div>
			</div>
			{frontmatter && frontmatter.series &&
				<Link to={collection && `/${collection}/${kebabCase(frontmatter.series)}/`}>
					<div className={cx("title", "series")} data-typesense-field="series">
						<span className="inline-svg"><FA icon="series" /></span> {frontmatter.series} Series
					</div>
				</Link>
			}
			<div className={cx("title")} data-typesense-field="title">{title}</div>
			{subtitle &&
				<div className={cx("title", "subtitle")} data-typesense-field={frontmatter.location ? "location" : "body"}>
					{subtitle}
				</div>
			}
		</div>
	)

}